import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { SafeAreaView, View, Text, Pressable, StyleSheet, ActivityIndicator, Alert } from 'react-native';
import * as WebBrowser from 'expo-web-browser';
import * as Linking from 'expo-linking';
import * as AuthSession from 'expo-auth-session';

WebBrowser.maybeCompleteAuthSession();

const OAUTH_CONFIG = {
  authorizationEndpoint: 'https://your-oauth-provider.com/oauth/authorize',
  tokenEndpoint: 'https://your-oauth-provider.com/oauth/token',
  revocationEndpoint: 'https://your-oauth-provider.com/oauth/revoke',
  clientId: 'mobile_app_client_123',
  redirectUri: AuthSession.makeRedirectUri({ useProxy: true }),
  scopes: ['openid', 'profile', 'email'],
};

function base64UrlEncode(input) {
  return btoa(input).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '');
}

async function sha256(plain) {
  const data = new TextEncoder().encode(plain);
  const digest = await globalThis.crypto.subtle.digest('SHA-256', data);
  const bytes = Array.from(new Uint8Array(digest));
  let binary = '';
  bytes.forEach((b) => {
    binary += String.fromCharCode(b);
  });
  return binary;
}

async function createPkcePair() {
  const verifier = AuthSession.generateRandom(64);
  const hashed = await sha256(verifier);
  const challenge = base64UrlEncode(hashed);
  return { verifier, challenge };
}

async function exchangeCodeForToken({ code, codeVerifier }) {
  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    client_id: OAUTH_CONFIG.clientId,
    code,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    code_verifier: codeVerifier,
  }).toString();

  const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body,
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`Token exchange failed: ${response.status} ${text}`);
  }

  return response.json();
}

async function refreshAccessToken(refreshToken) {
  const body = new URLSearchParams({
    grant_type: 'refresh_token',
    client_id: OAUTH_CONFIG.clientId,
    refresh_token: refreshToken,
  }).toString();

  const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body,
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`Refresh failed: ${response.status} ${text}`);
  }

  return response.json();
}

async function revokeToken(token) {
  if (!OAUTH_CONFIG.revocationEndpoint || !token) return;

  const body = new URLSearchParams({
    token,
    client_id: OAUTH_CONFIG.clientId,
  }).toString();

  await fetch(OAUTH_CONFIG.revocationEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body,
  });
}

export default function App() {
  const [loading, setLoading] = useState(false);
  const [tokenResponse, setTokenResponse] = useState(null);
  const [codeVerifier, setCodeVerifier] = useState(null);

  const discovery = useMemo(
    () => ({
      authorizationEndpoint: OAUTH_CONFIG.authorizationEndpoint,
      tokenEndpoint: OAUTH_CONFIG.tokenEndpoint,
      revocationEndpoint: OAUTH_CONFIG.revocationEndpoint,
    }),
    []
  );

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: OAUTH_CONFIG.clientId,
      redirectUri: OAUTH_CONFIG.redirectUri,
      scopes: OAUTH_CONFIG.scopes,
      responseType: AuthSession.ResponseType.Code,
      usePKCE: true,
    },
    discovery
  );

  useEffect(() => {
    if (request?.codeVerifier) {
      setCodeVerifier(request.codeVerifier);
    }
  }, [request]);

  useEffect(() => {
    const handleAuth = async () => {
      if (response?.type !== 'success') return;
      const code = response.params?.code;
      if (!code || !codeVerifier) return;

      try {
        setLoading(true);
        const tokens = await exchangeCodeForToken({ code, codeVerifier });
        setTokenResponse(tokens);
      } catch (e) {
        Alert.alert('Authentication Error', e.message);
      } finally {
        setLoading(false);
      }
    };

    handleAuth();
  }, [response, codeVerifier]);

  const signIn = useCallback(async () => {
    try {
      setLoading(true);
      await promptAsync({ useProxy: true });
    } catch (e) {
      Alert.alert('Login Error', e.message);
    } finally {
      setLoading(false);
    }
  }, [promptAsync]);

  const refresh = useCallback(async () => {
    if (!tokenResponse?.refresh_token) return;
    try {
      setLoading(true);
      const refreshed = await refreshAccessToken(tokenResponse.refresh_token);
      setTokenResponse((prev) => ({
        ...prev,
        ...refreshed,
        refresh_token: refreshed.refresh_token || prev?.refresh_token,
      }));
    } catch (e) {
      Alert.alert('Refresh Error', e.message);
    } finally {
      setLoading(false);
    }
  }, [tokenResponse]);

  const signOut = useCallback(async () => {
    try {
      setLoading(true);
      await revokeToken(tokenResponse?.access_token);
      setTokenResponse(null);
    } catch (e) {
      Alert.alert('Logout Error', e.message);
    } finally {
      setLoading(false);
    }
  }, [tokenResponse]);

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>OAuth 2.0 Mobile App</Text>
        <Text style={styles.subtitle}>Secure mobile auth using Authorization Code + PKCE</Text>

        {loading && <ActivityIndicator size="large" color="#2563eb" style={styles.loader} />}

        {!tokenResponse ? (
          <Pressable style={[styles.button, !request && styles.buttonDisabled]} onPress={signIn} disabled={!request || loading}>
            <Text style={styles.buttonText}>Sign In</Text>
          </Pressable>
        ) : (
          <>
            <View style={styles.tokenBox}>
              <Text style={styles.label}>Access Token</Text>
              <Text style={styles.value} numberOfLines={4}>
                {tokenResponse.access_token || 'N/A'}
              </Text>

              <Text style={styles.label}>Refresh Token</Text>
              <Text style={styles.value} numberOfLines={4}>
                {tokenResponse.refresh_token || 'N/A'}
              </Text>

              <Text style={styles.label}>Token Type</Text>
              <Text style={styles.value}>{tokenResponse.token_type || 'N/A'}</Text>

              <Text style={styles.label}>Expires In</Text>
              <Text style={styles.value}>{String(tokenResponse.expires_in ?? 'N/A')}</Text>
            </View>

            <Pressable style={styles.button} onPress={refresh} disabled={loading}>
              <Text style={styles.buttonText}>Refresh Token</Text>
            </Pressable>

            <Pressable style={[styles.button, styles.logoutButton]} onPress={signOut} disabled={loading}>
              <Text style={styles.buttonText}>Sign Out</Text>
            </Pressable>
          </>
        )}

        <Text style={styles.footer}>Redirect URI: {OAUTH_CONFIG.redirectUri}</Text>
      </View>
    </SafeAreaView>
  );
}

